import React, { useEffect, useState } from 'react'
import { useParams, Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux'

import './ProductScreen.css'
import Rating from '../components/Rating'
import ProductsList from '../components/ProductsList'
import { listProductDetails } from '../slices/product/productActions'


function ProductScreen() {
  const dispatch = useDispatch();
  const productDetails = useSelector(state => state.productDetails);
  const { error, loading, product } = productDetails

  const { id } = useParams();
  const [qty, setQty] = useState(0);
  const [countInStock, setCountInStock] = useState(0);
  const [relatedProducts, setRelatedProducts] = useState([]);

  useEffect( () => {
    dispatch(listProductDetails(id));

    async function fetchProduct(){
      const { data } = await axios.get(`/api/products/${id}/`);
      data.brand = data.brand.toUpperCase();
      setProduct(data);
      setCountInStock(data.countInStock);
    }
    fetchProduct();
  }, [dispatch, id]);

  useEffect( () => {
    async function fetchRelatedProducts(){
      const { data } = await axios.get('/api/products/');
      const result = data.filter(elem => elem.brand.toUpperCase() == product.brand)
      setRelatedProducts(result);
    }

    fetchRelatedProducts();

    // set default quantity for order to 1 if the product is in stock
    if(countInStock > 0) setQty(1);
  }, [product,]);



  return (
    <div>
      <div className='breadcrumbs'>
        <Link to='/'>Home</Link>/
        <Link to={product.category}>{product.category}</Link>/
        {product.name}
      </div>

      <div className='product'>

        <div className='left'>
            <img src={product.image}></img>
        </div>

        <div className='right'>
            <div className='name'>{product.name}</div>
            <Rating className='rating' value={product.rating} text={`(${product.numReviews})`} />
            <p className='price'>{product.price}&euro; - <span>{(countInStock > 0) ? <>In</> : <>Out of</>} Stock</span></p>
            <div className='qty'>
                <label>Quantity:</label>
                <select value={qty} onChange={(e) => setQty(e.target.value)}>
                    {[...new Array(countInStock+1).keys()].map((val) => {
                        return (<option key={val} value={val}>{val}</option>)
                    })}
                </select>
                
            </div>
            <p className='total'>Total: {qty * product.price}&euro;</p>
            <div className='add-product'>
                <button disabled={(countInStock > 0) ? false : true} className='cart'>Add to cart</button>
                <button className='wishlist'><i className='far fa-heart'/>&nbsp;&nbsp;Add to wishlist</button>
            </div>
            <p className='brand'>Brand: {product.brand}</p>
            <p className='desc'>{product.description}</p>
        </div>

      </div>

      <div className='related-products'>
        <h1 className='title'>Related products</h1>
        <ProductsList products={relatedProducts} />
      </div>
    </div>
  )
}

export default ProductScreen;
